-- ----------------------------
-- Table structure for drug_knowledge
-- ----------------------------
DROP TABLE IF EXISTS `drug_knowledge`;
CREATE TABLE `drug_knowledge`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '科普标题(如：什么是冰毒)',
  `category` varchar(50) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '毒品分类(如：传统毒品、新型合成毒品)',
  `cover_image` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '封面图',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '科普详细内容(可存储富文本或Markdown)',
  `is_deleted` tinyint(4) NOT NULL DEFAULT 0 COMMENT '逻辑删除：0-未删除，1-已删除',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '毒品类型科普表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of drug_knowledge
-- ----------------------------
INSERT INTO `drug_knowledge` VALUES (1, '新型毒品“奶茶”的伪装与危害', '新型合成毒品', NULL, '外观与普通冲泡奶茶无异，含有氯胺酮、MDMA等成分。此类毒品隐蔽性极强，吸食后会产生严重的幻觉和心率加速，对中枢神经系统造成不可逆的损伤。', 0, '2026-03-22 21:45:14', '2026-03-22 21:45:14');
INSERT INTO `drug_knowledge` VALUES (2, '传统毒品之王：海洛因的真相', '传统毒品', NULL, '海洛因俗称“白粉”，极易成瘾。长期吸食会导致免疫力全面丧失，器官功能衰竭，是社会危害性最大的毒品之一。', 0, '2026-03-22 21:45:14', '2026-03-22 21:45:14');
INSERT INTO `drug_knowledge` VALUES (3, '识破“邮票”毒品：LSD致幻剂', '新型合成毒品', NULL, '只有指甲盖大小的纸片，却含有强效致幻剂LSD。接触皮肤即可被吸收，产生长达12小时的严重幻觉，极易引发意外伤亡。', 0, '2026-03-22 21:45:14', '2026-03-22 21:45:14');
INSERT INTO `drug_knowledge` VALUES (4, '大麻的迷惑性与身体损伤', '传统毒品', NULL, '很多青少年误以为大麻不上瘾，实际上长期吸食大麻会产生强烈的心理依赖，导致记忆力减退、认知功能障碍及精神分裂症状。', 0, '2026-03-22 21:45:14', '2026-03-22 21:45:14');

