INSERT INTO `sys_announcement` VALUES (1, '关于举办2026年“阳光防线”禁毒知识竞赛的通知', '为了普及禁毒知识，平台将于下月举行在线竞赛，积分最高者可获得精美奖品。', 1, 0, '2026-03-22 21:45:25', '2026-03-22 21:45:25');
INSERT INTO `sys_announcement` VALUES (2, '平台“AI禁毒小助手”功能优化公告', '我们升级了AI模型，现在的回答将更加专业和温和，欢迎广大用户体验。', 1, 0, '2026-03-22 21:45:25', '2026-03-22 21:45:25');
INSERT INTO `sys_announcement` VALUES (3, '春季禁毒宣传社区行活动总结', '上周我校志愿者深入社区开展了禁毒宣传，发放手册1000余份，取得了圆满成功。', 1, 0, '2026-03-22 21:45:25', '2026-03-22 21:45:25');

