INSERT INTO `sys_news` VALUES (4, '识破“邮票”毒品的伪装', '这种毒品只有指甲盖大小，却含有强效致幻剂LSD，接触皮肤即可被吸收...', '新型毒品', 0, '2026-03-22 21:58:19', '2026-03-22 21:58:19');
INSERT INTO `sys_news` VALUES (5, '家庭禁毒教育指南', '家长应当如何引导青少年识别并拒绝新型毒品的诱惑...', '防范指南', 0, '2026-03-22 21:58:19', '2026-03-22 21:58:19');
