-- ----------------------------
-- Table structure for test_question
-- ----------------------------
DROP TABLE IF EXISTS `test_question`;
CREATE TABLE `test_question`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `question_text` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '题目内容',
  `question_type` tinyint(4) NOT NULL DEFAULT 1 COMMENT '题目类型：1-单选，2-多选，3-判断',
  `option_a` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '选项A',
  `option_b` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '选项B',
  `option_c` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '选项C',
  `option_d` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '选项D',
  `correct_answer` varchar(10) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '正确答案(如A, AB, True)',
  `analysis` varchar(500) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '答案解析',
  `is_deleted` tinyint(4) NOT NULL DEFAULT 0 COMMENT '逻辑删除',
  `create_time` datetime NULL DEFAULT CURRENT_TIMESTAMP COMMENT '创建时间',
  `update_time` datetime NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP COMMENT '更新时间',
  PRIMARY KEY (`id`) USING BTREE
) ENGINE = InnoDB AUTO_INCREMENT = 5 CHARACTER SET = utf8mb4 COLLATE = utf8mb4_general_ci COMMENT = '在线测试题库表' ROW_FORMAT = Dynamic;

-- ----------------------------
-- Records of test_question
-- ----------------------------
INSERT INTO `test_question` VALUES (1, '我国禁毒工作的方针是？', 1, '打击为主', '预防为主，综合治理', '科学研究', '社区康复', 'B', '根据《中华人民共和国禁毒法》，禁毒工作实行预防为主，综合治理，禁毒宣传教育、毒品管制、吸毒人员帮教并举的方针。', 0, '2026-03-22 21:45:41', '2026-03-22 21:45:41');
INSERT INTO `test_question` VALUES (2, '下列哪种物质属于新型合成毒品？', 1, '鸦片', '海洛因', '冰毒', '大麻', 'C', '冰毒属于人工化学合成的兴奋剂，属于第二代新型毒品；而鸦片、海洛因、大麻属于传统毒品。', 0, '2026-03-22 21:45:41', '2026-03-22 21:45:41');
INSERT INTO `test_question` VALUES (3, '长期吸食冰毒会导致什么样的严重后果？', 1, '身体强健', '增强记忆', '产生被害妄想和精神障碍', '没有副作用', 'C', '冰毒是强效中枢神经兴奋剂，会导致大脑受损，产生典型的精神分裂症症状。', 0, '2026-03-22 21:45:41', '2026-03-22 21:45:41');
INSERT INTO `test_question` VALUES (4, '如果发现身边有人吸毒，正确的做法是？', 1, '加入他们', '假装没看见', '及时向公安机关举报', '帮其隐瞒', 'C', '举报吸毒行为是每个公民的义务，也能帮助吸毒者尽早接受强制戒毒。', 0, '2026-03-22 21:45:41', '2026-03-22 21:45:41');

