DROP TABLE IF EXISTS `user_submission`;
CREATE TABLE `user_submission`  (
  `id` bigint(20) NOT NULL AUTO_INCREMENT COMMENT '主键',
  `user_id` bigint(20) NOT NULL COMMENT '投稿人ID',
  `title` varchar(100) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT '标题',
  `content` text CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NOT NULL COMMENT '留言/投稿内容',
  `ai_audit_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT 'AI预审状态：0-待审核，1-通过，2-不通过',
  `ai_audit_remark` varchar(255) CHARACTER SET utf8mb4 COLLATE utf8mb4_general_ci NULL DEFAULT NULL COMMENT 'AI审核意见',
  `manual_audit_status` tinyint(4) NOT NULL DEFAULT 0 COMMENT '人工审核状态：0-待审核，1-通过，2-不通过',
